//! Conformance tool definitions and dispatch.

use super::{ok, opt_str, rendered, req_str, str_array};
use lodestar_core::{Advice, ConformanceEvidence, Lodestar};
use serde_json::{json, Value};

pub(super) fn definitions() -> Vec<Value> {
    vec![
        json!({
            "name": "check_conformance",
            "description": "Evaluate a versioned, provenance-bearing ADR-0009 evidence bundle without changing task state.",
            "inputSchema": {
                "type": "object",
                "properties": {
                    "evidence": { "type": "object" },
                    "task_id": { "type": "string", "description": "Optional covering task." }
                },
                "required": ["evidence"]
            }
        }),
        json!({
            "name": "advise",
            "description": "Ask what governs an intended change BEFORE acting (ADR-0029). Given the node ids (artifact:/symbol:) you are about to change and an optional covering task, returns the active constitutional clauses governing that scope plus one proportional disposition: advise (proceed, honour any in-scope clauses) / review (would drift outside a covering task) / block (a forbid_change lock) / needs_human (no constitution adopted, or ambiguous). Evidence-free and state-free: it records no verdict and never gates a claim. Consult it at claim time and before editing governed code; retrospective check_conformance at complete_task remains the backstop.",
            "inputSchema": {
                "type": "object",
                "properties": {
                    "node_ids": { "type": "array", "items": { "type": "string" }, "description": "The artifact:/symbol: ids you intend to change." },
                    "task_id": { "type": "string", "description": "Optional covering task whose goal defines your scope." }
                },
                "required": ["node_ids"]
            }
        }),
        json!({
            "name": "conformance_history",
            "description": "Retrieve the durable, append-only conformance evidence chain for a task: each record's stable id, the recorded evidence bundle, verdict, findings, and checked_at — the resolvable link proving how (and whether) a task reached completion.",
            "inputSchema": {
                "type": "object",
                "properties": {
                    "task_id": { "type": "string" }
                },
                "required": ["task_id"]
            }
        }),
    ]
}

pub(super) fn dispatch(
    engine: &Lodestar,
    name: &str,
    args: &Value,
) -> Option<Result<Value, String>> {
    match name {
        "check_conformance" => Some((|| {
            let evidence = parse_evidence(args)?;
            let result = engine
                .check_conformance(&evidence, opt_str(args, "task_id").as_deref())
                .map_err(|e| e.to_string())?;
            ok(&result)
        })()),
        "advise" => Some((|| {
            let node_ids = str_array(args, "node_ids");
            let advice = engine
                .advise(opt_str(args, "task_id").as_deref(), &node_ids)
                .map_err(|e| e.to_string())?;
            rendered(render_advice(&advice), &advice)
        })()),
        "conformance_history" => Some((|| {
            ok(&engine
                .conformance_history(req_str(args, "task_id")?)
                .map_err(|e| e.to_string())?)
        })()),
        _ => None,
    }
}

pub(super) fn parse_evidence(args: &Value) -> Result<ConformanceEvidence, String> {
    let evidence = args
        .get("evidence")
        .cloned()
        .ok_or_else(|| "missing required object arg: evidence".to_string())?;
    serde_json::from_value(evidence).map_err(|error| format!("invalid evidence: {error}"))
}

/// Render `advise` output as chat Markdown: the headline disposition, the
/// human-readable findings, and a table of every clause governing the declared
/// scope. The structured `Advice` rides alongside in `structuredContent`.
fn render_advice(advice: &Advice) -> String {
    let mut markdown = format!(
        "**Advice: {}** - {} governing clause(s)\n",
        advice.disposition.as_str(),
        advice.governing.len()
    );
    for finding in &advice.findings {
        markdown.push_str(&format!("\n- {finding}"));
    }
    if !advice.governing.is_empty() {
        markdown.push_str("\n\n| Clause | Kind | Mode | Node |\n|---|---|---|---|\n");
        for clause in &advice.governing {
            markdown.push_str(&format!(
                "| {} | {} | {} | {} |\n",
                clause.goal.title,
                clause.goal.kind.as_str(),
                clause.mode.as_str(),
                clause.node_id
            ));
        }
    }
    markdown
}

#[cfg(test)]
mod tests {
    use super::super::call;
    use super::*;
    use lodestar_core::GoalKind;

    #[test]
    fn malformed_evidence_is_rejected_at_the_tool_boundary() {
        let engine = Lodestar::open_in_memory().unwrap();
        let params = json!({
            "name": "check_conformance",
            "arguments": { "evidence": { "schema_version": 1 } }
        });
        assert!(call(&engine, &params)
            .unwrap_err()
            .contains("invalid evidence"));
    }

    #[test]
    fn conformance_history_dispatch_returns_the_audit_chain() {
        let engine = Lodestar::open_in_memory().unwrap();
        let goal = engine
            .define_goal(GoalKind::Objective, "History", "prove it", None)
            .unwrap();
        let task = engine.create_task(&goal.id, "work", "done").unwrap();

        // No checks yet -> empty chain.
        let empty = call(
            &engine,
            &json!({ "name": "conformance_history", "arguments": { "task_id": task.id } }),
        )
        .unwrap();
        let records: Value =
            serde_json::from_str(empty["content"][0]["text"].as_str().unwrap()).unwrap();
        assert!(records.as_array().unwrap().is_empty());
    }

    #[test]
    fn advise_tool_reports_disposition_and_clauses_over_the_boundary() {
        use lodestar_core::CodeBindingMode;
        let engine = Lodestar::open_in_memory().unwrap();
        let goal = engine
            .define_goal(
                GoalKind::Constraint,
                "Payments boundary",
                "Payment code stays isolated.",
                None,
            )
            .unwrap();
        let node = "artifact:crates/pay/src/lib.rs".to_string();
        engine
            .link_goal_to_code(
                &goal.id,
                std::slice::from_ref(&node),
                CodeBindingMode::Governed,
            )
            .unwrap();

        // A governed node with no covering task would drift -> review, and the
        // governing clause is surfaced both in Markdown and structuredContent.
        let governed = call(
            &engine,
            &json!({ "name": "advise", "arguments": { "node_ids": [node] } }),
        )
        .unwrap();
        assert_eq!(governed["structuredContent"]["disposition"], "review");
        assert_eq!(
            governed["structuredContent"]["governing"][0]["goal"]["id"],
            goal.id
        );
        assert!(governed["content"][0]["text"]
            .as_str()
            .unwrap()
            .contains("Advice: review"));

        // An unbound node under an existing constitution is clear to proceed.
        let unbound = call(
            &engine,
            &json!({ "name": "advise", "arguments": { "node_ids": ["artifact:src/unrelated.rs"] } }),
        )
        .unwrap();
        assert_eq!(unbound["structuredContent"]["disposition"], "advise");
        assert!(unbound["structuredContent"]["governing"]
            .as_array()
            .unwrap()
            .is_empty());
    }
}
